/***
 * Compile Period: yesterday
 ***/
const PERIOD = 'yesterday';
const rows = $input.all().map(i => i.json || {});

function toNum(v) {
  if (v == null || v === '') return 0;
  const n = Number(String(v).replace(/,/g,'.').replace(/[^0-9.\-]/g,''));
  return Number.isFinite(n) ? n : 0;
}
function normChannel(v) {
  const s = String(v || '').toUpperCase().replace(/[_\s]/g,' ').trim();
  if (s.includes('SEARCH')) return 'SEARCH';
  if (s.includes('PERFORMANCE') || s.includes('PMAX') || s.includes('MAX')) return 'PERFORMANCE MAX';
  return s || 'OTHER';
}
const safeDiv = (n, d) => (d && Number.isFinite(n) && Number.isFinite(d)) ? n/d : 0;

function compileRows(rows) {
  const byId = {};
  for (const r of rows) {
    const id   = String(r.campaign_id   || '').trim();
    const name = String(r.campaign_name || '').trim();
    const ch   = normChannel(r.channel  || '');
    if (!id && !name) continue;
    const key = id || name;
    if (!byId[key]) byId[key] = {id, name, channel:ch, imp:0, clk:0, spend:0, conv:0, value:0};
    byId[key].imp   += toNum(r.impressions);
    byId[key].clk   += toNum(r.clicks);
    byId[key].spend += toNum(r.cost);
    byId[key].conv  += toNum(r.conversions);
    byId[key].value += toNum(r.conv_value);
  }
  const campaigns = Object.values(byId).map(c => ({
    ...c,
    ctr:  safeDiv(c.clk,   c.imp),
    cpc:  safeDiv(c.spend, c.clk),
    cvr:  safeDiv(c.conv,  c.clk),
    roas: safeDiv(c.value, c.spend),
  }));
  const totals = {imp:0, clicks:0, spend:0, conv:0, value:0};
  for (const c of campaigns) {
    totals.imp    += c.imp;
    totals.clicks += c.clk;
    totals.spend  += c.spend;
    totals.conv   += c.conv;
    totals.value  += c.value;
  }
  totals.ctr  = safeDiv(totals.clicks, totals.imp);
  totals.cpc  = safeDiv(totals.spend,  totals.clicks);
  totals.cvr  = safeDiv(totals.conv,   totals.clicks);
  totals.roas = safeDiv(totals.value,  totals.spend);
  const byChannel = {};
  for (const c of campaigns) {
    const ch = c.channel;
    if (!byChannel[ch]) byChannel[ch] = {imp:0, clicks:0, spend:0, conv:0, value:0};
    byChannel[ch].imp    += c.imp;
    byChannel[ch].clicks += c.clk;
    byChannel[ch].spend  += c.spend;
    byChannel[ch].conv   += c.conv;
    byChannel[ch].value  += c.value;
  }
  for (const b of Object.values(byChannel)) {
    b.ctr  = safeDiv(b.clicks, b.imp);
    b.cpc  = safeDiv(b.spend,  b.clicks);
    b.roas = safeDiv(b.value,  b.spend);
  }
  const ranked = campaigns.filter(c => c.spend >= 10).sort((a,b) => b.roas - a.roas);
  return { totals, by_channel: byChannel, campaigns,
           top3_labels: ranked.slice(0,3).map(c=>c.name),
           bottom3_labels: ranked.slice(-3).map(c=>c.name).reverse() };
}

const result = compileRows(rows);
return [{ json: { period: PERIOD, brand: 'MM', ...result } }];

