/***
 * Detect Anomalies + Prep Daily Payload
 * Thresholds: CPC +25%, CTR -20% vs 7-day avg.
 * Also checks DoD changes and spend pacing.
 ***/
const all = $input.all().map(i => i.json);
const yesterday = all.find(i => i.period === 'yesterday');
const dod       = all.find(i => i.period === 'day_before_yesterday');
const avg7d     = all.find(i => i.period === 'last_7_days');

if (!yesterday) throw new Error('Missing yesterday data. Periods received: ' + all.map(i=>i.period).join(', '));

const safeDiv = (n,d) => (d && Number.isFinite(n) && Number.isFinite(d)) ? n/d : 0;
const pctChange = (cur, base) => (base > 0) ? (cur - base) / base : null;

const CPC_SPIKE  =  0.25;  // +25%
const CTR_DROP   = -0.20;  // -20%
const ROAS_DROP  = -0.30;  // -30%
const MIN_SPEND  = 20;     // min €20 spend to check campaign-level
const anomalies  = [];

const y = yesterday.totals;
const a = avg7d?.totals || {};

// ── Overall metrics vs 7-day avg ──
const checks = [
  { key:'cpc',   delta: pctChange(y.cpc,  a.cpc),  threshold: CPC_SPIKE,  direction: 'up',   label:'CPC',   unit:'€' },
  { key:'ctr',   delta: pctChange(y.ctr,  a.ctr),  threshold: CTR_DROP,   direction: 'down', label:'CTR',   unit:'%' },
  { key:'roas',  delta: pctChange(y.roas, a.roas),  threshold: ROAS_DROP,  direction: 'down', label:'Campaign efficiency', unit:'' },
];

for (const c of checks) {
  if (c.delta === null) continue;
  const triggered = c.direction === 'up' ? c.delta > c.threshold : c.delta < c.threshold;
  if (!triggered) continue;
  const severity = Math.abs(c.delta) > Math.abs(c.threshold) * 2 ? 'critical' : 'warning';
  anomalies.push({
    type: `${c.key.toUpperCase()}_ANOMALY`, severity, scope: 'overall', metric: c.label,
    yesterday: y[c.key], baseline: a[c.key], change_pct: c.delta,
    message: `Overall ${c.label} ${c.direction} ${(Math.abs(c.delta)*100).toFixed(1)}% vs 7-day avg`,
  });
}

// ── Spend pacing vs 7-day daily avg ──
if (a.daily_spend > 0) {
  const spendDelta = pctChange(y.spend, a.daily_spend);
  if (spendDelta > 0.5) {
    anomalies.push({
      type: 'SPEND_SPIKE', severity: 'warning', scope: 'overall', metric: 'Spend',
      yesterday: y.spend, baseline: a.daily_spend, change_pct: spendDelta,
      message: `Daily spend €${y.spend.toFixed(0)} is ${(spendDelta*100).toFixed(0)}% above 7-day daily avg`,
    });
  }
}

// ── Per-campaign vs 7-day avg ──
for (const camp of (yesterday.campaigns || [])) {
  if (camp.spend < MIN_SPEND) continue;
  const c7d = (avg7d?.campaigns || []).find(c => c.id === camp.id || c.name === camp.name);
  if (!c7d) continue;
  const cpcΔ = pctChange(camp.cpc,  c7d.cpc);
  const ctrΔ = pctChange(camp.ctr,  c7d.ctr);
  if (cpcΔ !== null && cpcΔ > CPC_SPIKE)
    anomalies.push({ type:'CAMPAIGN_CPC', severity:'warning', scope:'campaign', campaign:camp.name,
      metric:'CPC', change_pct:cpcΔ, message:`"${camp.name}": CPC +${(cpcΔ*100).toFixed(1)}%` });
  if (ctrΔ !== null && ctrΔ < CTR_DROP)
    anomalies.push({ type:'CAMPAIGN_CTR', severity:'warning', scope:'campaign', campaign:camp.name,
      metric:'CTR', change_pct:ctrΔ, message:`"${camp.name}": CTR ${(ctrΔ*100).toFixed(1)}%` });
}

// ── DoD comparison ──
const dod_changes = {};
if (dod) {
  const d = dod.totals;
  dod_changes.spend  = pctChange(y.spend,  d.spend);
  dod_changes.clicks = pctChange(y.clicks, d.clicks);
  dod_changes.conv   = pctChange(y.conv,   d.conv);
  dod_changes.cpc    = pctChange(y.cpc,    d.cpc);
  dod_changes.ctr    = pctChange(y.ctr,    d.ctr);
  dod_changes.roas   = pctChange(y.roas,   d.roas);
}

const date = new Date(); date.setDate(date.getDate() - 1);
return [{ json: {
  brand: 'MM', date: date.toISOString().split('T')[0],
  yesterday, dod_baseline: dod || null, rolling_7d: avg7d || null,
  dod_changes, anomalies,
  has_anomalies: anomalies.length > 0,
  has_critical: anomalies.some(a => a.severity === 'critical'),
  anomaly_count: anomalies.length,
}}];

/***
 * Format Daily Slack Blocks
 * Input: merged item with anomaly payload + AI agent output
 ***/
const all  = $input.all().map(i => i.json);
const data = all.find(i => i.brand === 'MM' && i.date !== undefined) || all[0];
const ai   = (all.find(i => i.output !== undefined) || {}).output || '';

const y   = data.yesterday?.totals   || {};
const a   = data.rolling_7d?.totals  || {};
const dod = data.dod_changes          || {};

const fmtEur  = n => `€${Number(n||0).toLocaleString('de-DE',{minimumFractionDigits:2,maximumFractionDigits:2})}`;
const fmtNum  = n => Number(n||0).toLocaleString('de-DE');
const fmtPct  = (n, noSign) => n == null ? 'n/a' : `${n>=0&&!noSign?'+':''}${(n*100).toFixed(1)}%`;
const fmtRoas = n => Number(n||0).toFixed(2);

const statusEmoji = data.has_critical ? '🚨' : data.has_anomalies ? '⚠️' : '✅';
const statusLabel = data.has_critical ? 'Critical Alert' : data.has_anomalies ? `${data.anomaly_count} Anomaly` : 'All Clear';

const blocks = [
  {
    type: 'header',
    text: { type: 'plain_text', text: `${statusEmoji} MM Daily Paid – ${data.date} · ${statusLabel}`, emoji: true }
  },
  { type: 'divider' },
  {
    type: 'section',
    text: { type: 'mrkdwn', text: '*Yesterday at a glance*' },
    fields: [
      { type: 'mrkdwn', text: `*Spend*\n${fmtEur(y.spend)}` },
      { type: 'mrkdwn', text: `*Clicks*\n${fmtNum(y.clicks)}` },
      { type: 'mrkdwn', text: `*Conversions*\n${fmtNum(y.conv)}` },
      { type: 'mrkdwn', text: `*Efficiency*\n${fmtRoas(y.roas)}` },
    ]
  },
  {
    type: 'section',
    text: { type: 'mrkdwn', text: '*vs 7-day rolling average*' },
    fields: [
      { type: 'mrkdwn', text: `*CPC*\n${fmtEur(y.cpc)} _(${fmtPct(a.cpc>0?(y.cpc-a.cpc)/a.cpc:null)} vs avg ${fmtEur(a.cpc)})_` },
      { type: 'mrkdwn', text: `*CTR*\n${fmtPct(y.ctr,true)} _(${fmtPct(a.ctr>0?(y.ctr-a.ctr)/a.ctr:null)} vs avg)_` },
      { type: 'mrkdwn', text: `*Spend*\n${fmtEur(y.spend)} _(${fmtPct(a.daily_spend>0?(y.spend-a.daily_spend)/a.daily_spend:null)} vs daily avg)_` },
      { type: 'mrkdwn', text: `*DoD*\n${Object.keys(dod).length ? `Spend ${fmtPct(dod.spend)}, CPC ${fmtPct(dod.cpc)}` : 'n/a'}` },
    ]
  },
];

// Channel split
const chKeys = Object.keys(data.yesterday?.by_channel || {});
if (chKeys.length > 0) {
  const chLines = chKeys.map(ch => {
    const b = data.yesterday.by_channel[ch];
    return `• *${ch}*: ${fmtEur(b.spend)} spend · ${fmtNum(b.clicks)} clicks · eff. ${fmtRoas(b.roas)}`;
  }).join('\n');
  blocks.push({ type: 'divider' });
  blocks.push({ type: 'section', text: { type: 'mrkdwn', text: `*Channel breakdown*\n${chLines}` } });
}

// Anomalies
if (data.has_anomalies) {
  const lines = (data.anomalies||[]).map(a => `${a.severity==='critical'?'🚨':'⚠️'} ${a.message}`).join('\n');
  blocks.push({ type: 'divider' });
  blocks.push({
    type: 'section',
    text: { type: 'mrkdwn', text: `*${data.has_critical?'🚨 Critical alerts':'⚠️ Anomalies detected'} (${data.anomaly_count})*\n${lines}` }
  });
}

// AI commentary
if (ai) {
  blocks.push({ type: 'divider' });
  blocks.push({ type: 'section', text: { type: 'mrkdwn', text: `*💡 Analysis*\n${ai.slice(0,3000)}` } });
}

blocks.push({ type: 'divider' });
blocks.push({
  type: 'context',
  elements: [{ type: 'mrkdwn', text: `_MindMeister Paid · Daily Monitor · ${new Date().toISOString().split('T')[0]}_` }]
});

const fallback = `${statusEmoji} MM Daily Paid – ${data.date} | Spend: ${fmtEur(y.spend)} | CPC: ${fmtEur(y.cpc)} | Eff: ${fmtRoas(y.roas)}${data.has_anomalies?' | '+statusLabel:''}`;
return [{ json: { blocks, text: fallback } }];

