      { type: 'mrkdwn', text: `*Spend*\n${fmtEur(last.spend)}\n_${fmtMom(mom.spend)} MoM_` },
      { type: 'mrkdwn', text: `*Clicks*\n${fmtNum(last.clicks)}\n_${fmtMom(mom.clicks)} MoM_` },
      { type: 'mrkdwn', text: `*Conversions*\n${fmtNum(last.conv)}\n_${fmtMom(mom.conv)} MoM_` },
      { type: 'mrkdwn', text: `*Efficiency*\n${fmtRoas(last.roas)}\n_${fmtMom(mom.roas)} MoM_` },
      { type: 'mrkdwn', text: `*CPC*\n${fmtEur(last.cpc)}\n_${fmtMom(mom.cpc)} MoM_` },
      { type: 'mrkdwn', text: `*CTR*\n${((last.ctr||0)*100).toFixed(2)}%\n_${fmtMom(mom.ctr)} MoM_` },
    ]
  },
];

if (budget.total_budget > 0) {
  blocks.push({ type: 'section',
    text: { type: 'mrkdwn', text: `*Budget*   ${fmtEur(budget.total_spend)} of ${fmtEur(budget.total_budget)} (${budget.pct_spent}%)  · ${fmtEur(budget.leftover)} leftover` }
  });
}

const chKeys = Object.keys(ch);
if (chKeys.length > 0) {
  const chLines = chKeys.map(k => {
    const b = ch[k];
    return `• *${k}*: ${fmtEur(b.spend)} · ${fmtNum(b.conv)} conv · eff. ${fmtRoas(b.roas)} · CTR ${((b.ctr||0)*100).toFixed(2)}% · CPC ${fmtEur(b.cpc)}`;
  }).join('\n');
  blocks.push({ type: 'divider' });
  blocks.push({ type: 'section', text: { type: 'mrkdwn', text: `*Channel breakdown*\n${chLines}` } });
}

const top3    = mm.highs_lows?.top3    || mm.last?.top3_labels    || [];
const bottom3 = mm.highs_lows?.bottom3 || mm.last?.bottom3_labels || [];
if (top3.length || bottom3.length) {
  blocks.push({ type: 'divider' });
  blocks.push({ type: 'section', fields: [
    { type: 'mrkdwn', text: `*🏆 Top campaigns (efficiency)*\n${top3.map((n,i)=>`${i+1}. ${n}`).join('\n')||'n/a'}` },
    { type: 'mrkdwn', text: `*⚠️ Bottom campaigns*\n${bottom3.map((n,i)=>`${i+1}. ${n}`).join('\n')||'n/a'}` },
  ]});
}

if (ai) {
  blocks.push({ type: 'divider' });
  blocks.push({ type: 'section', text: { type: 'mrkdwn', text: `*💡 Analysis & Recommendations*\n${ai.slice(0,3000)}` } });
}

blocks.push({ type: 'divider' });
blocks.push({ type: 'context', elements: [{ type: 'mrkdwn', text: `_MindMeister Paid · Monthly Report · ${meta.month_label||''}_` }] });
return [{ json: { blocks, text: `📆 MM Monthly Google Ads – ${meta.month_label||'Last Month'} | Spend: ${fmtEur(last.spend)} | Eff: ${fmtRoas(last.roas)}` } }];
